// ==========================================
// Procesamiento robusto de mensajes de Slack
// ==========================================

function levenshtein(a, b) {
  const m = a.length, n = b.length;
  if (m === 0) return n;
  if (n === 0) return m;
  const dp = Array.from({ length: m + 1 }, () => new Array(n + 1).fill(0));
  for (let i = 0; i <= m; i++) dp[i][0] = i;
  for (let j = 0; j <= n; j++) dp[0][j] = j;
  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      const cost = a[i - 1] === b[j - 1] ? 0 : 1;
      dp[i][j] = Math.min(
        dp[i - 1][j] + 1,
        dp[i][j - 1] + 1,
        dp[i - 1][j - 1] + cost
      );
    }
  }
  return dp[m][n];
}

try {
  const event = ($json && $json.body && $json.body.event) || {};
  const rawText = typeof event.text === "string" ? event.text : "";

  const MAX_LENGTH = 2000;
  let message = rawText.slice(0, MAX_LENGTH);

  // Limpieza de formato Slack (menciones, canales, links, markdown)
  message = message
    .replace(/<@[A-Z0-9]+>/gi, " ")
    .replace(/<#[A-Z0-9]+\|?([^>]*)>/gi, " $1 ")
    .replace(/<!(here|channel|everyone)>/gi, " ")
    .replace(/<(https?:\/\/[^|>]+)\|([^>]+)>/gi, " $2 ")
    .replace(/<(https?:\/\/[^>]+)>/gi, " ")
    .replace(/[*_~`]/g, " ");

  // Normalización básica
  message = message
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^\p{L}\p{N}\s]/gu, " ")
    .replace(/\s+/g, " ")
    .trim();

  // Correcciones (Map evita el bug de keys duplicadas del objeto original)
  const corrections = new Map([
    ["vacasiones", "vacaciones"],
    ["vacacion", "vacaciones"],
    ["vacacioneses", "vacaciones"],
    ["dockerr", "docker"],
    ["dokcer", "docker"],
    ["dock", "docker"],
    ["workflows", "workflow"],
    ["work flow", "workflow"],
    ["git hub", "github"],
    ["vpnn", "vpn"],
    ["desplegar", "deployment"],
    ["deploy", "deployment"],
    ["despliegue", "deployment"]
  ]);

  // Frases largas primero, para que no las pise una corrección más corta
  const sortedCorrections = [...corrections.entries()].sort(
    (a, b) => b[0].length - a[0].length
  );
  for (const [wrong, right] of sortedCorrections) {
    const escaped = wrong.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
    message = message.replace(new RegExp(`\\b${escaped}\\b`, "gi"), right);
  }

  const stopWords = new Set([
    "como", "quiero", "puedo", "hacer", "para", "donde", "cuando",
    "que", "una", "uno", "los", "las", "del", "con", "por",
    "ayuda", "favor", "el", "la", "de", "en", "y", "o", "un",
    "necesito", "podrias", "podrías", "tengo", "hola", "buenas"
  ]);

  const canonicalTerms = ["vacaciones", "docker", "vpn", "deployment", "github", "workflow"];

  // Fuzzy matching: atrapa typos que no están en el diccionario de correcciones
  function fuzzyCorrect(word) {
    if (word.length < 4) return word;
    for (const term of canonicalTerms) {
      const maxDist = term.length <= 5 ? 1 : 2;
      if (levenshtein(word, term) <= maxDist) return term;
    }
    return word;
  }

  let keywords = message
    .split(/\s+/)
    .filter(Boolean)
    .filter(word => word.length > 2)
    .filter(word => !stopWords.has(word))
    .map(fuzzyCorrect);

  const synonyms = {

  // Docker / Infraestructura
  docker: [
    "docker",
    "compose",
    "container",
    "contenedor"
  ],

  contenedor: [
    "docker",
    "container",
    "compose"
  ],

  compose: [
    "docker",
    "compose"
  ],


  // Workflows / Automatización
  workflow: [
    "workflow",
    "n8n",
    "automation"
  ],

  workflows: [
    "workflow",
    "n8n",
    "automation"
  ],

  flujo: [
    "workflow",
    "automation"
  ],

  automatizacion: [
    "workflow",
    "n8n",
    "automation"
  ],


  // Deployment
  desplegar: [
    "deployment",
    "deploy",
    "release"
  ],

  desplegamos: [
    "deployment",
    "deploy",
    "release"
  ],

  despliegue: [
    "deployment",
    "deploy"
  ],

  publicar: [
    "deployment",
    "release"
  ],


  // VPN
  vpn: [
    "vpn",
    "remote",
    "access"
  ],


  // HR
  vacaciones: [
    "vacaciones",
    "vacation",
    "leave",
    "hr"
  ],

  vacacion: [
    "vacaciones",
    "vacation",
    "leave",
    "hr"
  ],

  vacasiones: [
    "vacaciones",
    "vacation",
    "leave",
    "hr"
  ]
};

  const expandedKeywords = new Set(keywords);
  keywords.forEach(keyword => {
    if (synonyms[keyword]) synonyms[keyword].forEach(s => expandedKeywords.add(s));
  });

  return [
    {
      json: {
        original_question: rawText,
        normalized_question: message,
        keywords: [...expandedKeywords],
        channel: event.channel || null,
        user: event.user || null,
        has_content: keywords.length > 0,
        processed_at: new Date().toISOString()
      }
    }
  ];
} catch (error) {
  return [
    {
      json: {
        original_question: ($json?.body?.event?.text) || "",
        normalized_question: "",
        keywords: [],
        channel: ($json?.body?.event?.channel) || null,
        user: ($json?.body?.event?.user) || null,
        has_content: false,
        error: error.message,
        processed_at: new Date().toISOString()
      }
    }
  ];
}

const keywords = $json.keywords;

return keywords.map(keyword => ({
  json: {
    search_term: keyword
  }
}));

const keywords = $json.keywords || [];

const synonymMap = {

  docker: [
    "docker",
    "container",
    "contenedor",
    "compose",
    "imagen",
    "servicio"
  ],

  restart: [
    "restart",
    "reiniciar",
    "reinicio",
    "levantar",
    "arrancar",
    "recrear"
  ],

  deployment: [
  "deployment",
  "deploy",
  "release",
  "docker",
  "compose"
],

 workflow: [
  "workflow",
  "flujo",
  "automatizacion",
  "n8n",
  "deployment",
  "docker"
],

  vacation: [
    "vacaciones",
    "vacation",
    "permiso",
    "dias",
    "ausencia"
  ],

  vpn: [
    "vpn",
    "conexion",
    "acceso",
    "red"
  ],

  api: [
    "api",
    "endpoint",
    "servicio",
    "integracion"
  ]

};


let expanded = [...keywords];


keywords.forEach(word => {

  for (const concept in synonymMap) {

    if (synonymMap[concept].includes(word)) {

      expanded.push(...synonymMap[concept]);

    }

  }

});


return [
  {
    json:{
      keywords:[...new Set(expanded)]
    }
  }
];

const keywords = $json.keywords || [];


return items.map(item => {

  const documentText = (
    item.json.name +
    " " +
    (item.json.mimeType || "")
  ).toLowerCase();


  let score = 0;


  keywords.forEach(keyword => {

    const matches = (
      documentText.match(
        new RegExp(keyword, "g")
      ) || []
    ).length;


    score += matches;

  });


  // Prioridad a documentación útil
  const mime = item.json.mimeType || "";


  if (
    mime === "text/markdown" ||
    mime.includes("pdf") ||
    mime.includes("wordprocessingml")
  ) {
    score += 2;
  }


  return {
    json:{
      ...item.json,
      score
    }
  };


})
.sort(
(a,b)=>b.json.score-a.json.score
);

return items.filter(item => {

  const mime = item.json.mimeType;

  const supportedTypes = [
    "text/markdown",
    "text/plain",
    "application/pdf",
    "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
    "application/vnd.google-apps.document"
  ];

  return supportedTypes.includes(mime);

});

const seen = new Set();

return items.filter(item => {

  const id = item.json.id;

  if (seen.has(id)) {
    return false;
  }

  seen.add(id);
  return true;

});

const MAX_DOCUMENTS = 5;
const MAX_CHARS_PER_DOCUMENT = 8000;

const documents = [];
const sources = [];

const rankingItem = $items("Documents Ranking")[sources.length];

for (const item of items.slice(0, MAX_DOCUMENTS)) {

  const text =
    item.json.data ||
    item.json.text ||
    item.json.content ||
    "";

  if (!text.trim()) continue;

const title =
    rankingItem?.json?.name ||
    item.json.name ||
    item.json.fileName ||
    item.json.filename ||
    `Documento ${sources.length + 1}`;

  sources.push(title);

documents.push(
`### DOCUMENTO
Nombre: ${title}

Contenido:
${text.substring(0, MAX_CHARS_PER_DOCUMENT)}`
);

}

return [{
  json: {
    question: $items("Extract Event")[0].json.question,
    context: documents.join("\n\n----------------------------------------\n\n"),
    sources,
    documentCount: sources.length
  }
}];
